import React, { useState, useContext } from 'react';
import StaffLayout from '../../components/Layouts/StaffLayout';
import { DataContext } from '../../context/DataContext';
import { AuthContext } from '../../context/AuthContext';

const FacilityCheck = () => {
  const { submitFacilityReport } = useContext(DataContext);
  const { user } = useContext(AuthContext);

  const checklistItems = [
    "Hệ thống đèn chiếu sáng", "Máy lạnh / Quạt", "Máy tính / Màn hình", 
    "Vệ sinh khu vực làm việc", "Cửa ra vào / Khóa"
  ];

  const [checks, setChecks] = useState({});
  const [reportType, setReportType] = useState('start'); // start | end

  const handleCheck = (item) => {
    setChecks({ ...checks, [item]: !checks[item] });
  };

  // Yêu cầu 7: Phải tick hết mới gửi được
  const allChecked = checklistItems.every(item => checks[item]);

  const handleSubmit = () => {
    if (!allChecked) return;
    
    submitFacilityReport({
        reporterName: user.name || "Nhân viên",
        type: reportType,
        items: checklistItems,
        note: ''
    });

    alert("Gửi báo cáo CSVC thành công!");
    setChecks({}); // Reset
  };

  return (
    <StaffLayout>
      <div className="p-4">
        <h2 className="text-2xl font-bold mb-6">Kiểm tra Cơ sở vật chất</h2>

        <div className="bg-white p-6 rounded shadow max-w-lg mx-auto">
            <div className="flex gap-4 mb-6">
                <button 
                    className={`flex-1 py-2 rounded ${reportType === 'start' ? 'bg-blue-600 text-white' : 'bg-gray-200'}`}
                    onClick={() => setReportType('start')}>Đầu giờ</button>
                <button 
                    className={`flex-1 py-2 rounded ${reportType === 'end' ? 'bg-blue-600 text-white' : 'bg-gray-200'}`}
                    onClick={() => setReportType('end')}>Cuối giờ</button>
            </div>

            <div className="space-y-3 mb-6">
                {checklistItems.map((item, idx) => (
                    <label key={idx} className="flex items-center p-3 border rounded cursor-pointer hover:bg-gray-50">
                        <input type="checkbox" className="w-5 h-5 mr-3"
                            checked={!!checks[item]} onChange={() => handleCheck(item)} />
                        <span>{item}</span>
                    </label>
                ))}
            </div>

            <button 
                onClick={handleSubmit} 
                disabled={!allChecked}
                className={`w-full py-3 rounded font-bold text-lg transition-colors
                    ${allChecked ? 'bg-green-600 text-white hover:bg-green-700' : 'bg-gray-300 text-gray-500 cursor-not-allowed'}`}>
                GỬI BÁO CÁO
            </button>
            {!allChecked && <p className="text-center text-red-500 text-sm mt-2">Vui lòng kiểm tra tất cả các mục.</p>}
        </div>
      </div>
    </StaffLayout>
  );
};

export default FacilityCheck;
